const numbersToWords=f=>{const O=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(f<0x14)return O[f];if(f<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](f/0xa)]+(f%0xa?'\x20'+O[f%0xa]:'');if(f<0x3e8){const M=Math['floor'](f/0x64),k=f%0x64;return(0x1===M?'εκατό':0x2===M?'διακόσια':0x3===M?'τριακόσια':0x4===M?'τετρακόσια':0x5===M?'πεντακόσια':0x6===M?'εξακόσια':0x7===M?'επτακόσια':0x8===M?'οκτακόσια':0x9===M?'εννιακόσια':'')+(k?'\x20'+numbersToWords(k):'');}return f<0xf4240?numbersToWords(Math['floor'](f/0x3e8))+'\x20χιλιάδες'+(f%0x3e8?'\x20'+numbersToWords(f%0x3e8):''):numbersToWords(Math['floor'](f/0xf4240))+'\x20εκατομμύρια'+(f%0xf4240?'\x20'+numbersToWords(f%0xf4240):'');},numberToText=(f,O='money')=>{const M=Math['floor'](f),k=Math['round'](0x64*(f-M));let K=numbersToWords(M),L=k>0x0?numbersToWords(k):'';switch(O){case'money':return L?K+'\x20ευρώ\x20και\x20'+L+'\x20λεπτά':K+'\x20ευρώ';case'time':return L?K+'\x20ώρες\x20και\x20'+L+'\x20λεπτά':K+'\x20ώρες';default:return L?K+'\x20και\x20'+L:''+K;}};